-- Supabase PostgreSQL Schema for Seefar Food Delivery Platform
-- Generated for React Native Expo App

-- Enable necessary extensions
CREATE EXTENSION IF NOT EXISTS "uuid-ossp";
CREATE EXTENSION IF NOT EXISTS "pgcrypto";

-- Users table (no FK dependencies)
CREATE TABLE IF NOT EXISTS public.users (
  id uuid PRIMARY KEY REFERENCES auth.users(id) ON DELETE CASCADE,
  name text,
  email text UNIQUE,
  phone text,
  avatar text,
  "defaultAddressId" uuid,
  "referralCode" text,
  created_at timestamptz DEFAULT now()
);

ALTER TABLE public.users ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Users can view their own profile" ON public.users
  FOR SELECT USING (auth.uid() = id);

CREATE POLICY "Users can update their own profile" ON public.users
  FOR UPDATE USING (auth.uid() = id);

CREATE INDEX IF NOT EXISTS idx_users_email ON public.users(email);
CREATE INDEX IF NOT EXISTS idx_users_phone ON public.users(phone);

-- Restaurants table (no FK dependencies)
CREATE TABLE IF NOT EXISTS public.restaurants (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  name text NOT NULL,
  cuisine text,
  rating numeric,
  "reviewCount" integer DEFAULT 0,
  "deliveryTime" text,
  "deliveryFee" numeric,
  "minOrder" numeric,
  image text,
  address text,
  phone text,
  "operatingHours" text,
  latitude numeric,
  longitude numeric,
  created_at timestamptz DEFAULT now()
);

ALTER TABLE public.restaurants ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Restaurants are viewable by everyone" ON public.restaurants
  FOR SELECT USING (true);

CREATE INDEX IF NOT EXISTS idx_restaurants_cuisine ON public.restaurants(cuisine);
CREATE INDEX IF NOT EXISTS idx_restaurants_rating ON public.restaurants(rating);
CREATE INDEX IF NOT EXISTS idx_restaurants_location ON public.restaurants(latitude, longitude);

-- Drivers table (no FK dependencies)
CREATE TABLE IF NOT EXISTS public.drivers (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  name text NOT NULL,
  phone text,
  avatar text,
  vehicle text,
  "licensePlate" text,
  rating numeric,
  "currentLatitude" numeric,
  "currentLongitude" numeric,
  status text,
  created_at timestamptz DEFAULT now()
);

ALTER TABLE public.drivers ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Drivers are viewable by everyone" ON public.drivers
  FOR SELECT USING (true);

CREATE INDEX IF NOT EXISTS idx_drivers_status ON public.drivers(status);

-- Payment methods table (FK: users)
CREATE TABLE IF NOT EXISTS public.payment_methods (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  "userId" uuid NOT NULL REFERENCES public.users(id) ON DELETE CASCADE,
  type text,
  last4 text,
  brand text,
  "isDefault" boolean DEFAULT false,
  created_at timestamptz DEFAULT now()
);

ALTER TABLE public.payment_methods ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Users can view their own payment methods" ON public.payment_methods
  FOR SELECT USING (auth.uid() = "userId");

CREATE POLICY "Users can insert their own payment methods" ON public.payment_methods
  FOR INSERT WITH CHECK (auth.uid() = "userId");

CREATE POLICY "Users can update their own payment methods" ON public.payment_methods
  FOR UPDATE USING (auth.uid() = "userId");

CREATE POLICY "Users can delete their own payment methods" ON public.payment_methods
  FOR DELETE USING (auth.uid() = "userId");

CREATE INDEX IF NOT EXISTS idx_payment_methods_user ON public.payment_methods("userId");

-- Addresses table (FK: users)
CREATE TABLE IF NOT EXISTS public.addresses (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  "userId" uuid NOT NULL REFERENCES public.users(id) ON DELETE CASCADE,
  label text,
  street text,
  apartment text,
  city text,
  zipcode text,
  latitude numeric,
  longitude numeric,
  "isDefault" boolean DEFAULT false,
  instructions text,
  created_at timestamptz DEFAULT now()
);

ALTER TABLE public.addresses ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Users can view their own addresses" ON public.addresses
  FOR SELECT USING (auth.uid() = "userId");

CREATE POLICY "Users can insert their own addresses" ON public.addresses
  FOR INSERT WITH CHECK (auth.uid() = "userId");

CREATE POLICY "Users can update their own addresses" ON public.addresses
  FOR UPDATE USING (auth.uid() = "userId");

CREATE POLICY "Users can delete their own addresses" ON public.addresses
  FOR DELETE USING (auth.uid() = "userId");

CREATE INDEX IF NOT EXISTS idx_addresses_user ON public.addresses("userId");

-- Menu items table (FK: restaurants)
CREATE TABLE IF NOT EXISTS public.menu_items (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  "restaurantId" uuid NOT NULL REFERENCES public.restaurants(id) ON DELETE CASCADE,
  name text NOT NULL,
  description text,
  price numeric,
  image text,
  category text,
  "isPopular" boolean DEFAULT false,
  created_at timestamptz DEFAULT now()
);

ALTER TABLE public.menu_items ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Menu items are viewable by everyone" ON public.menu_items
  FOR SELECT USING (true);

CREATE INDEX IF NOT EXISTS idx_menu_items_restaurant ON public.menu_items("restaurantId");
CREATE INDEX IF NOT EXISTS idx_menu_items_category ON public.menu_items(category);

-- Customizations table (FK: menu_items)
CREATE TABLE IF NOT EXISTS public.customizations (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  "menuItemId" uuid NOT NULL REFERENCES public.menu_items(id) ON DELETE CASCADE,
  name text NOT NULL,
  required boolean DEFAULT false,
  "maxSelections" integer,
  created_at timestamptz DEFAULT now()
);

ALTER TABLE public.customizations ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Customizations are viewable by everyone" ON public.customizations
  FOR SELECT USING (true);

CREATE INDEX IF NOT EXISTS idx_customizations_menu_item ON public.customizations("menuItemId");

-- Customization options table (FK: customizations)
CREATE TABLE IF NOT EXISTS public.customization_options (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  "customizationId" uuid NOT NULL REFERENCES public.customizations(id) ON DELETE CASCADE,
  name text NOT NULL,
  price numeric,
  created_at timestamptz DEFAULT now()
);

ALTER TABLE public.customization_options ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Customization options are viewable by everyone" ON public.customization_options
  FOR SELECT USING (true);

CREATE INDEX IF NOT EXISTS idx_customization_options_customization ON public.customization_options("customizationId");

-- Orders table (FK: restaurants, users, addresses, payment_methods, drivers)
CREATE TABLE IF NOT EXISTS public.orders (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  "restaurantId" uuid NOT NULL REFERENCES public.restaurants(id) ON DELETE RESTRICT,
  "userId" uuid NOT NULL REFERENCES public.users(id) ON DELETE CASCADE,
  subtotal numeric,
  "deliveryFee" numeric,
  "serviceFee" numeric,
  tip numeric,
  "totalPrice" numeric,
  "deliveryAddressId" uuid REFERENCES public.addresses(id) ON DELETE SET NULL,
  "paymentMethodId" uuid REFERENCES public.payment_methods(id) ON DELETE SET NULL,
  status text,
  "driverId" uuid REFERENCES public.drivers(id) ON DELETE SET NULL,
  "estimatedDelivery" timestamptz,
  rating integer,
  review text,
  created_at timestamptz DEFAULT now(),
  updated_at timestamptz DEFAULT now()
);

ALTER TABLE public.orders ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Users can view their own orders" ON public.orders
  FOR SELECT USING (auth.uid() = "userId");

CREATE POLICY "Users can insert their own orders" ON public.orders
  FOR INSERT WITH CHECK (auth.uid() = "userId");

CREATE POLICY "Users can update their own orders" ON public.orders
  FOR UPDATE USING (auth.uid() = "userId");

CREATE INDEX IF NOT EXISTS idx_orders_user ON public.orders("userId");
CREATE INDEX IF NOT EXISTS idx_orders_restaurant ON public.orders("restaurantId");
CREATE INDEX IF NOT EXISTS idx_orders_driver ON public.orders("driverId");
CREATE INDEX IF NOT EXISTS idx_orders_status ON public.orders(status);
CREATE INDEX IF NOT EXISTS idx_orders_created_at ON public.orders(created_at);

-- Order items table (FK: orders, menu_items)
CREATE TABLE IF NOT EXISTS public.order_items (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  "orderId" uuid NOT NULL REFERENCES public.orders(id) ON DELETE CASCADE,
  "menuItemId" uuid NOT NULL REFERENCES public.menu_items(id) ON DELETE RESTRICT,
  quantity integer,
  "specialInstructions" text,
  "totalPrice" numeric,
  created_at timestamptz DEFAULT now()
);

ALTER TABLE public.order_items ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Order items are viewable by order owner" ON public.order_items
  FOR SELECT USING (
    "orderId" IN (
      SELECT id FROM public.orders WHERE "userId" = auth.uid()
    )
  );

CREATE INDEX IF NOT EXISTS idx_order_items_order ON public.order_items("orderId");
CREATE INDEX IF NOT EXISTS idx_order_items_menu_item ON public.order_items("menuItemId");

-- Order item customizations table (FK: order_items, customizations)
CREATE TABLE IF NOT EXISTS public.order_item_customizations (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  "orderItemId" uuid NOT NULL REFERENCES public.order_items(id) ON DELETE CASCADE,
  "customizationId" uuid NOT NULL REFERENCES public.customizations(id) ON DELETE RESTRICT,
  "optionIds" text[],
  created_at timestamptz DEFAULT now()
);

ALTER TABLE public.order_item_customizations ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Order item customizations are viewable by order owner" ON public.order_item_customizations
  FOR SELECT USING (
    "orderItemId" IN (
      SELECT id FROM public.order_items WHERE "orderId" IN (
        SELECT id FROM public.orders WHERE "userId" = auth.uid()
      )
    )
  );

CREATE INDEX IF NOT EXISTS idx_order_item_customizations_order_item ON public.order_item_customizations("orderItemId");
CREATE INDEX IF NOT EXISTS idx_order_item_customizations_customization ON public.order_item_customizations("customizationId");

-- Reviews table (FK: orders, users, restaurants)
CREATE TABLE IF NOT EXISTS public.reviews (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  "orderId" uuid NOT NULL REFERENCES public.orders(id) ON DELETE CASCADE,
  "userId" uuid NOT NULL REFERENCES public.users(id) ON DELETE CASCADE,
  "userName" text,
  "userAvatar" text,
  "restaurantId" uuid NOT NULL REFERENCES public.restaurants(id) ON DELETE CASCADE,
  rating integer,
  comment text,
  created_at timestamptz DEFAULT now()
);

ALTER TABLE public.reviews ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Reviews are viewable by everyone" ON public.reviews
  FOR SELECT USING (true);

CREATE POLICY "Users can insert their own reviews" ON public.reviews
  FOR INSERT WITH CHECK (auth.uid() = "userId");

CREATE POLICY "Users can update their own reviews" ON public.reviews
  FOR UPDATE USING (auth.uid() = "userId");

CREATE POLICY "Users can delete their own reviews" ON public.reviews
  FOR DELETE USING (auth.uid() = "userId");

CREATE INDEX IF NOT EXISTS idx_reviews_order ON public.reviews("orderId");
CREATE INDEX IF NOT EXISTS idx_reviews_user ON public.reviews("userId");
CREATE INDEX IF NOT EXISTS idx_reviews_restaurant ON public.reviews("restaurantId");

-- Handle new user signup
CREATE OR REPLACE FUNCTION public.handle_new_user()
RETURNS trigger LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$
BEGIN
  INSERT INTO public.users (id, email, name, phone, avatar, "referralCode", created_at)
  VALUES (
    NEW.id,
    NEW.email,
    NEW.raw_user_meta_data ->> 'name',
    NEW.raw_user_meta_data ->> 'phone',
    NEW.raw_user_meta_data ->> 'avatar',
    NEW.raw_user_meta_data ->> 'referralCode',
    now()
  )
  ON CONFLICT (id) DO NOTHING;
  RETURN NEW;
END; $$;

DROP TRIGGER IF EXISTS on_auth_user_created ON auth.users;
CREATE TRIGGER on_auth_user_created AFTER INSERT ON auth.users FOR EACH ROW EXECUTE FUNCTION public.handle_new_user();

-- Add foreign key constraint for users.defaultAddressId after addresses table exists
ALTER TABLE public.users
ADD CONSTRAINT fk_users_default_address
FOREIGN KEY ("defaultAddressId") REFERENCES public.addresses(id) ON DELETE SET NULL;

-- === Deterministic CRUD policies for user-owned tables (generated by SupabaseConfigAgent) ===
-- Every table with a direct or transitive ownership path to auth.users gets INSERT/UPDATE/DELETE
-- policies so client-side writes by the owner succeed while cross-user writes are blocked.
-- Idempotent: safe to re-run.
DROP POLICY IF EXISTS "Users can insert own payment_methods" ON public."payment_methods";
CREATE POLICY "Users can insert own payment_methods" ON public."payment_methods" FOR INSERT WITH CHECK (auth.uid() = "userId");
DROP POLICY IF EXISTS "Users can update own payment_methods" ON public."payment_methods";
CREATE POLICY "Users can update own payment_methods" ON public."payment_methods" FOR UPDATE USING (auth.uid() = "userId") WITH CHECK (auth.uid() = "userId");
DROP POLICY IF EXISTS "Users can delete own payment_methods" ON public."payment_methods";
CREATE POLICY "Users can delete own payment_methods" ON public."payment_methods" FOR DELETE USING (auth.uid() = "userId");

DROP POLICY IF EXISTS "Users can insert own addresses" ON public."addresses";
CREATE POLICY "Users can insert own addresses" ON public."addresses" FOR INSERT WITH CHECK (auth.uid() = "userId");
DROP POLICY IF EXISTS "Users can update own addresses" ON public."addresses";
CREATE POLICY "Users can update own addresses" ON public."addresses" FOR UPDATE USING (auth.uid() = "userId") WITH CHECK (auth.uid() = "userId");
DROP POLICY IF EXISTS "Users can delete own addresses" ON public."addresses";
CREATE POLICY "Users can delete own addresses" ON public."addresses" FOR DELETE USING (auth.uid() = "userId");

DROP POLICY IF EXISTS "Users can insert own orders" ON public."orders";
CREATE POLICY "Users can insert own orders" ON public."orders" FOR INSERT WITH CHECK (auth.uid() = "userId");
DROP POLICY IF EXISTS "Users can update own orders" ON public."orders";
CREATE POLICY "Users can update own orders" ON public."orders" FOR UPDATE USING (auth.uid() = "userId") WITH CHECK (auth.uid() = "userId");
DROP POLICY IF EXISTS "Users can delete own orders" ON public."orders";
CREATE POLICY "Users can delete own orders" ON public."orders" FOR DELETE USING (auth.uid() = "userId");

DROP POLICY IF EXISTS "Users can insert own order_items" ON public."order_items";
CREATE POLICY "Users can insert own order_items" ON public."order_items" FOR INSERT WITH CHECK ("orderId" IN (SELECT "id" FROM public."orders" WHERE "userId" = auth.uid()));
DROP POLICY IF EXISTS "Users can update own order_items" ON public."order_items";
CREATE POLICY "Users can update own order_items" ON public."order_items" FOR UPDATE USING ("orderId" IN (SELECT "id" FROM public."orders" WHERE "userId" = auth.uid())) WITH CHECK ("orderId" IN (SELECT "id" FROM public."orders" WHERE "userId" = auth.uid()));
DROP POLICY IF EXISTS "Users can delete own order_items" ON public."order_items";
CREATE POLICY "Users can delete own order_items" ON public."order_items" FOR DELETE USING ("orderId" IN (SELECT "id" FROM public."orders" WHERE "userId" = auth.uid()));

DROP POLICY IF EXISTS "Users can insert own reviews" ON public."reviews";
CREATE POLICY "Users can insert own reviews" ON public."reviews" FOR INSERT WITH CHECK (auth.uid() = "userId");
DROP POLICY IF EXISTS "Users can update own reviews" ON public."reviews";
CREATE POLICY "Users can update own reviews" ON public."reviews" FOR UPDATE USING (auth.uid() = "userId") WITH CHECK (auth.uid() = "userId");
DROP POLICY IF EXISTS "Users can delete own reviews" ON public."reviews";
CREATE POLICY "Users can delete own reviews" ON public."reviews" FOR DELETE USING (auth.uid() = "userId");


-- === Deterministic storage.objects policies (generated by SupabaseConfigAgent) ===
-- Every declared bucket gets owner-scoped INSERT/UPDATE/DELETE policies using the
-- first path segment as the owner uid. Public buckets additionally get public-read
-- SELECT so getPublicUrl(...) resolves instead of returning "Bucket not found" 404.
-- Idempotent: safe to re-run.
DROP POLICY IF EXISTS "avatars_public_read" ON storage.objects;
CREATE POLICY "avatars_public_read" ON storage.objects FOR SELECT TO public USING (bucket_id = 'avatars');
DROP POLICY IF EXISTS "avatars_owner_insert" ON storage.objects;
CREATE POLICY "avatars_owner_insert" ON storage.objects FOR INSERT TO authenticated WITH CHECK (bucket_id = 'avatars' AND (storage.foldername(name))[1] = auth.uid()::text);
DROP POLICY IF EXISTS "avatars_owner_update" ON storage.objects;
CREATE POLICY "avatars_owner_update" ON storage.objects FOR UPDATE TO authenticated USING (bucket_id = 'avatars' AND (storage.foldername(name))[1] = auth.uid()::text) WITH CHECK (bucket_id = 'avatars' AND (storage.foldername(name))[1] = auth.uid()::text);
DROP POLICY IF EXISTS "avatars_owner_delete" ON storage.objects;
CREATE POLICY "avatars_owner_delete" ON storage.objects FOR DELETE TO authenticated USING (bucket_id = 'avatars' AND (storage.foldername(name))[1] = auth.uid()::text);

DROP POLICY IF EXISTS "restaurant-images_public_read" ON storage.objects;
CREATE POLICY "restaurant-images_public_read" ON storage.objects FOR SELECT TO public USING (bucket_id = 'restaurant-images');
DROP POLICY IF EXISTS "restaurant-images_owner_insert" ON storage.objects;
CREATE POLICY "restaurant-images_owner_insert" ON storage.objects FOR INSERT TO authenticated WITH CHECK (bucket_id = 'restaurant-images' AND (storage.foldername(name))[1] = auth.uid()::text);
DROP POLICY IF EXISTS "restaurant-images_owner_update" ON storage.objects;
CREATE POLICY "restaurant-images_owner_update" ON storage.objects FOR UPDATE TO authenticated USING (bucket_id = 'restaurant-images' AND (storage.foldername(name))[1] = auth.uid()::text) WITH CHECK (bucket_id = 'restaurant-images' AND (storage.foldername(name))[1] = auth.uid()::text);
DROP POLICY IF EXISTS "restaurant-images_owner_delete" ON storage.objects;
CREATE POLICY "restaurant-images_owner_delete" ON storage.objects FOR DELETE TO authenticated USING (bucket_id = 'restaurant-images' AND (storage.foldername(name))[1] = auth.uid()::text);

DROP POLICY IF EXISTS "menu-items_owner_insert" ON storage.objects;
CREATE POLICY "menu-items_owner_insert" ON storage.objects FOR INSERT TO authenticated WITH CHECK (bucket_id = 'menu-items' AND (storage.foldername(name))[1] = auth.uid()::text);
DROP POLICY IF EXISTS "menu-items_owner_update" ON storage.objects;
CREATE POLICY "menu-items_owner_update" ON storage.objects FOR UPDATE TO authenticated USING (bucket_id = 'menu-items' AND (storage.foldername(name))[1] = auth.uid()::text) WITH CHECK (bucket_id = 'menu-items' AND (storage.foldername(name))[1] = auth.uid()::text);
DROP POLICY IF EXISTS "menu-items_owner_delete" ON storage.objects;
CREATE POLICY "menu-items_owner_delete" ON storage.objects FOR DELETE TO authenticated USING (bucket_id = 'menu-items' AND (storage.foldername(name))[1] = auth.uid()::text);
